(6, 'hero_title', '\"Selamat Datang di SDN 3 Karang Kedawung\"', '2026-07-07 07:30:16', '2026-07-07 07:30:51'),
(7, 'hero_description', '\"Membangun masa depan bangsa bersama generasi gemilang, tangguh, dan terampil dalam berbagai aspek.\"', '2026-07-07 07:30:16', '2026-07-07 07:32:12'),
